using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder - Happy Path

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(20.00m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(36.50m, order.Total); // (10*2) + (5.5*3)
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToApproximatelyNow()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Item", 1.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Item", 1.00m, 1));

        // Act
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder - Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Item", 1.00m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var items = CreateItems(("Item", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        // Arrange
        var items = CreateItems(("Item", 1.00m, 1));
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        // Act
        var orders = _sut.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, orders.Count);
    }

    #endregion

    #region Total Calculation - Parameterized

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single item qty 1")]
    [DataRow(7.50, 4, 30.00, DisplayName = "Single item qty 4")]
    [DataRow(0.01, 100, 1.00, DisplayName = "Penny x 100")]
    public void CreateOrder_VariousPricesAndQuantities_CalculatesCorrectTotal(
        double price, int qty, double expectedTotal)
    {
        // Arrange
        var items = CreateItems(("Product", (decimal)price, qty));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion
}

